import os
import re
from threading import Lock, Event
from datetime import datetime
from rtSque.loggers import safe_convert_ts
from collections import OrderedDict

import levels
from reportlogger import FileLogger
from rtSque.sequencer.sequencer import SKIP_ITEM
from publisher import NoOpPublisher, timestamp


def synchronized(func):
    def wrapper(self, *args, **kwargs):
        with self._lock:
            return func(self, *args, **kwargs)
    return wrapper


class CSVLogger(FileLogger):
    _lock = Lock()
    header_written_event = Event()

    class CSVRun(object):
        def __init__(self, ts):
            self.sn = ''
            self.items = OrderedDict()
            self.start_ts = ts
            self.result = ''
            self.fail_list = ''

    def post_init(self):
        self.header_written_event.clear()
        # self.create_log('NA')
        # initial log with empty sequence name as sequence_load event could happen before logger is ready
        self.runs = None
        self.cases_tid = []

    def create_log(self, seq_name):
        ts = datetime.strftime(datetime.now(), "%Y-%m-%d-%H-%M-%S")
        filename = self.product + '_' + self.station_type + '_' + seq_name + '_' + ts + '_all.csv'
        if not os.path.exists(os.path.join(self.log_folder, 'CSV')):
            os.mkdir(os.path.join(self.log_folder, 'CSV'))
        log_path = os.path.join(self.log_folder, 'CSV', filename)
        self.log_paths = log_path
        with open(self.log_paths, 'w+') as fd:
            fd.write('Product,SerialNumber,Station ID,Site_ID,PASS/FAIL,Error_Message,Failed_List,Test Start Time,'
                             'Test Stop Time,')
            fd.flush()
        self.header_written_event.clear()

    def on_sequence_start(self, site, data):
        self.runs = self.CSVRun(data['timestamp'])
        for item in self.cases_tid:
            self.runs.items[item] = {}

    def on_item_start(self, site, data):
        if 'subsubtestname' in data.keys():

            item = dict(tid=data['group'] + ' ' + data['subtestname'] + '@' + data['subsubtestname'],
                        low=data['lowerlimit'], high=data['upperlimit'], unit=data['units'], result='')
        else:

            item = dict(tid=data['group'] + '@' + data['subtestname'],
                        low=data['lowerlimit'], high=data['upperlimit'], unit=data['units'], result='')
        self.runs.items[item['tid']] = item

    def on_item_finish(self, site, data):
        if 'subsubtestname' in data.keys():
            key = '{} {}@{}'.format(data['group'], data['tid'], data['subsubtestname'])
        else:
            key = '{}@{}'.format(data['group'], data['tid'])
        if 'value' in data:
            result = str(data['value'])
        else:
            result = str(data['error'])
        self.runs.items[key]['result'] = result.replace(',', ';')
        if data['result'] < 1:
            self.runs.fail_list += key + ';'

    def on_attribute_found(self, site, data):
        if 'mlbsn' in data['name'].lower():
            self.runs.sn = data['value']

    @synchronized
    def on_sequence_end(self, site, data):
        with open(self.log_paths, 'a+') as fd:
            if not self.header_written_event.isSet():
                self.header_written_event.set()
                skip_fields = ',,,,,,,,,'
                if not hasattr(self, "case_list"):
                    for item in self.runs.items.values():
                        fd.write(item['tid'] + ',')
                    fd.write("\n" + 'Upper Limit----------->' + skip_fields)
                    for item in self.runs.items.values():
                        fd.write(item['high'] + ',')
                    fd.write("\n" + 'Lower Limit----------->' + skip_fields)
                    for item in self.runs.items.values():
                        fd.write(item['low'] + ',')
                    fd.write("\n" + 'Measurement unit------>' + skip_fields)
                    for item in self.runs.items.values():
                        fd.write(item['unit'] + ',')
                else:
                    for item in self.case_list:
                        if "SubSubTestName" in item[1]:
                             fd.write(re.findall('Group[\']*: [\\\']+([^,]*)[\\\']+', item[1])[0] + ' ')
                             fd.write(re.findall('SubTestName[\']*: [\\\']+([^,]*)[\\\']+', item[1])[0] + '@')
                             fd.write(re.findall('SubSubTestName[\']*: [\\\']+([^,]*)[\\\']+', item[1])[0] + ',')
                        else:
                            fd.write(re.findall('Group[\']*: [\\\']+([^,]*)[\\\']+', item[1])[0] + '@')
                            fd.write(re.findall('SubTestName[\']*: [\\\']+([^,]*)[\\\']+', item[1])[0] + ',')
                    fd.write("\n" + 'Upper Limit----------->' + skip_fields)
                    for item in self.case_list:
                        fd.write(re.findall('UpperLimit[\']*: [\\\']+([^,]*)[\\\']+', item[1])[0] + ',')
                    fd.write("\n" + 'Lower Limit----------->' + skip_fields)
                    for item in self.case_list:
                        fd.write(re.findall('LowerLimit[\']*: [\\\']+([^,]*)[\\\']+', item[1])[0] + ',')
                    fd.write("\n" + 'Measurement unit------>' + skip_fields)
                    for item in self.case_list:
                        fd.write(re.findall('Units[\']*: [\\\']+([^,]*)[\\\']+', item[1])[0] + ',')
                fd.write("\n")
                fd.flush()

            if data['result'] > 0:
                self.runs.result = 'PASS'
            else:
                self.runs.result = 'FAIL'
            msg = ''
            if 'error_msg' in data:
                msg = data.get('error_msg', '')
            if ',' in msg:
                msg = msg.replace(',', ';')
            line = '{0},{1},{2},{3},{4},{5},{6},{7},{8}'.format(
                                                                self.product,        # Product
                                                                self.runs.sn,        # SerialNumber
                                                                self.station_id,     # Station_ID
                                                                site,                # Site_ID
                                                                self.runs.result,    # PASS/FAIL
                                                                msg,                 # Error_Message
                                                                self.runs.fail_list, # Failed_List
                                                                self.runs.start_ts,  # Test Start Time
                                                                datetime.now(),      # Test Stop Time
                                                                )
            for item in self.runs.items.values():
                if 'result' in item:
                    line = line + ',' + str(item['result'])
                else:
                    line = line + ',' + 'SKIP'
            fd.write(line + "\n")
            fd.flush()

    def on_sequence_loaded(self, site, data):
        self.release_log(0, 0)
        self.create_log(data['name'])
        self.cases_tid = []
        if 'case_list' in data.keys():
            self.case_list = data['case_list'][1:]
            for case in self.case_list:
                if "SubSubTestName" in case[1]:
                    tid = re.findall('Group[\']*: [\\\']+([^,]*)[\\\']+', case[1])[0]+ ' ' +  re.findall('SubTestName[\']*: [\\\']+([^,]*)[\\\']+', case[1])[0]+ '@' +  re.findall('SubSubTestName[\']*: [\\\']+([^,]*)[\\\']+', case[1])[0]
                else:
                    tid = re.findall('Group[\']*: [\\\']+([^,]*)[\\\']+', case[1])[0]+ '@' +  re.findall('SubTestName[\']*: [\\\']+([^,]*)[\\\']+', case[1])[0]
                self.cases_tid.append(tid)

    def get_log_path(self, site):
        return ''


class PivotLogger(FileLogger):

    def post_sequence_start(self, site, data):
        # Pending for a different way to detect presence of subsubtestname. --Andrew Cheng. --2019/5/9
        # Corresponding change in on_item_finish required. --Andrew Cheng. --2019/5/9
        # if 'subsubtestname' in data.keys():
        #     self.write(site, 0, 'site,sn,testname,subtestname,subsubtestname,unit,low,high,month,day,hour,minute,second,microsec,result,value,fail_msg\n')
        # else:
        #     self.write(site, 0, 'site,sn,testname,subtestname,unit,low,high,month,day,hour,minute,second,microsec,result,value,fail_msg\n')
        self.write(site, 0, 'site,sn,testname,subtestname,subsubtestname,unit,low,high,month,day,hour,minute,second,microsec,result,value,fail_msg\n')
    
    def on_item_start(self, site, data):
        if 'subsubtestname' in data.keys():
            item = dict(group=data['group'], tid=data['subtestname'], subsubtestname=data['subsubtestname'], unit=data['units'],
                        low=data['lowerlimit'], high=data['upperlimit'], result='', msg='')
            key = '{}-{}-{}'.format(data['group'], data['subtestname'], data['subsubtestname'])
        else:
            item = dict(group=data['group'], tid=data['subtestname'], unit=data['units'],
                        low=data['lowerlimit'], high=data['upperlimit'], result='', msg='')
            key = '{}-{}'.format(data['group'], data['subtestname'])
        self.device.running_item[key] = item

    def on_item_finish(self, site, data):
        dut = self.device
        if 'subsubtestname' in data.keys():
            key = '{}-{}-{}'.format(data['group'], data['tid'], data['subsubtestname'])
            item = dut.running_item[key]
            self.write(
                site, 0,
                '%d,%s,%s,%s,%s,%s,%s,%s,' % (site, dut.sn, item['group'], item['tid'], item['subsubtestname'], item['unit'], item['low'], item['high'])
            )
        else:
            key = '{}-{}'.format(data['group'], data['tid'])
            item = dut.running_item[key]
            self.write(
                site, 0,
                '%d,%s,%s,%s,,%s,%s,%s,' % (site, dut.sn, item['group'], item['tid'], item['unit'], item['low'], item['high'])
            )
        self.write(site, 0, safe_convert_ts(data['timestamp'], '%Y-%m-%d %H:%M:%S.%f', '%m,%d,%H,%M,%S,%f,'))
        res = data['result']
        if res == True:
            self.write(site, 0, 'Pass' + ',')
        elif res == SKIP_ITEM:
            self.write(site, 0, 'Skip' + ',')
        else:
            self.write(site, 0, 'Fail' + ',')
        if 'error' in data:
            error = str(data['error'])
            if ',' in error:
                error = error.replace(',', ';')
            self.write(site, 0, ',' + error)
        else:
            value = str(data['value'])
            if ',' in value:
                value = value.replace(',', ';')
            self.write(site, 0, value + ',')
        self.write(site, 0, os.linesep)
        self.uut_sn = str(dut.sn)

    def on_attribute_found(self, site, data):
        if 'mlbsn' in data['name'].lower():
            self.device.sn = data['value']


def flow_log_item_start(self, site, data):
    """

    :param self:
    :param site:
    :param data:
    """
    if 'subsubtestname' in data.keys():
        item = dict(group=data['group'], tid=data['subtestname'], subsubtestname=data['subsubtestname'], unit=data['units'], low=data['lowerlimit'], high=data['upperlimit'],
                    result='', msg='')
        key = '{}-{}-{}'.format(data['group'], data['subtestname'], data['subsubtestname'])
    else:
        item = dict(group=data['group'], tid=data['subtestname'], unit=data['units'], low=data['lowerlimit'], high=data['upperlimit'],
                    result='', msg='')
        key = '{}-{}'.format(data['group'], data['subtestname'])
    self.device.running_item[key] = item
    self.write(site, 0, '==Test: ' + item['group'] + os.linesep)
    self.write(site, 0, '==SubTest: ' + item['tid'] + os.linesep)
    if 'subsubtestname' in data.keys():
        self.write(site, 0, '==SubSubTest: ' + item['subsubtestname'] + os.linesep)
    return


def flow_log_item_finish(self, site, data):
    """

    :param self:
    :param site:
    :param data:
    """
    if 'subsubtestname' in data.keys():
        key = '{}-{}-{}'.format(data['group'], data['tid'], data['subsubtestname'])
    else:
        key = '{}-{}'.format(data['group'], data['tid'])
    item = self.device.running_item[key]
    if 'error' in data:
        value = str(data['error'])
    else:
        value = str(data['value'])
    self.write(site, 0, '\t\t\tlower:{0}; upper:{1}; value:{2}'.format(item['low'], item['high'], value) + os.linesep)
    res = data['result']
    if res == True:
        result = 'PASS'
    elif res == SKIP_ITEM:
        result = 'SKIP'
    else:
        result = 'FAIL'
    self.write(site, 0, data['timestamp'] + ' ' * 3 + result + os.linesep)
    return
